from dataclasses import dataclass
from pii_scanner import scan_text, Finding

@dataclass
class ValidationResult:
    session_id: str
    production_findings: list[Finding]   # what production scanner found and redacted
    validation_findings: list[Finding]   # what validation scanner found in sanitised output
    leaked_pii: list[Finding]            # validation_findings not covered by production

    @property
    def leakage_count(self) -> int:
        return len(self.leaked_pii)

    @property
    def is_leak(self) -> bool:
        return len(self.leaked_pii) > 0


def validate_redacted_output(
    sanitised_text: str,
    production_findings: list[Finding],
    session_id: str,
    strict_threshold: float = 0.5,   # lower than production (0.7)
) -> ValidationResult:
    """
    Re-scan the sanitised output with a strict threshold.
    Any PII found here is a production leak.
    """
    val_result = scan_text(sanitised_text, block_on_critical=False)

    # Filter to findings above the strict threshold
    val_findings = [f for f in val_result.findings if f.confidence >= strict_threshold]

    # PII in the sanitised output = leakage (production failed to redact it)
    leaked = [
        f for f in val_findings
        # Exclude redaction tokens that look like PII (e.g., [EMAIL_1] contains @-like chars)
        if not (f.value.startswith("[") and f.value.endswith("]"))
    ]

    return ValidationResult(
        session_id=session_id,
        production_findings=production_findings,
        validation_findings=val_findings,
        leaked_pii=leaked,
    )

from pathlib import Path
import json

TEST_CORPUS_PATH = Path("/var/data/pii/test_corpus.jsonl")

def regression_test(
    min_precision: float = 0.92,
    min_recall: float = 0.85,
) -> dict:
    """
    Run the current scanner against the labeled test corpus.
    Returns per-entity metrics and a pass/fail verdict.
    """
    from collections import defaultdict
    from pii_scanner import scan_text

    stats = defaultdict(lambda: {"tp": 0, "fp": 0, "fn": 0})

    for line in TEST_CORPUS_PATH.read_text().splitlines():
        if not line.strip():
            continue
        doc = json.loads(line)
        truth = {(s["type"], s["start"], s["end"]) for s in doc.get("spans", [])}
        result = scan_text(doc["text"], block_on_critical=False)
        predicted = {(f.entity_type, f.start, f.end) for f in result.findings}

        for span in predicted:
            stats[span[0]]["tp" if span in truth else "fp"] += 1
        for span in truth:
            if span not in predicted:
                stats[span[0]]["fn"] += 1

    metrics = {}
    overall_tp = overall_fp = overall_fn = 0
    for et, s in stats.items():
        tp, fp, fn = s["tp"], s["fp"], s["fn"]
        prec = tp / (tp + fp) if (tp + fp) > 0 else 0.0
        rec  = tp / (tp + fn) if (tp + fn) > 0 else 0.0
        metrics[et] = {"precision": round(prec, 3), "recall": round(rec, 3)}
        overall_tp += tp; overall_fp += fp; overall_fn += fn

    overall_prec = overall_tp / (overall_tp + overall_fp) if (overall_tp + overall_fp) else 0.0
    overall_rec  = overall_tp / (overall_tp + overall_fn) if (overall_tp + overall_fn) else 0.0

    passed = (overall_prec >= min_precision and overall_rec >= min_recall)
    return {
        "passed": passed,
        "overall_precision": round(overall_prec, 3),
        "overall_recall": round(overall_rec, 3),
        "per_entity": metrics,
    }
